class Solution:
    def minimumMoves(self, grid):
        n = len(grid)
        from collections import deque
        # state: (r, c, h) tail at (r,c); h=0 horizontal occupies (r,c),(r,c+1)
        # h=1 vertical occupies (r,c),(r+1,c)
        start = (0, 0, 0)
        goal = (n - 1, n - 2, 0)
        def free(r, c):
            return 0 <= r < n and 0 <= c < n and grid[r][c] == 0
        # plain BFS over an explicit visited dict, distinct from the optimal's set
        dist = {start: 0}
        q = deque([start])
        while q:
            r, c, h = q.popleft()
            d = dist[(r, c, h)]
            nbrs = []
            if h == 0:
                if free(r, c + 2):
                    nbrs.append((r, c + 1, 0))
                if free(r + 1, c) and free(r + 1, c + 1):
                    nbrs.append((r + 1, c, 0))
                    nbrs.append((r, c, 1))
            else:
                if free(r, c + 1) and free(r + 1, c + 1):
                    nbrs.append((r, c + 1, 1))
                    nbrs.append((r, c, 0))
                if free(r + 2, c):
                    nbrs.append((r + 1, c, 1))
            for s in nbrs:
                if s not in dist:
                    dist[s] = d + 1
                    q.append(s)
        return dist.get(goal, -1)

