class Solution:
    def minimumMoves(self, grid):
        n = len(grid)
        from collections import deque
        def free(r, c):
            return 0 <= r < n and 0 <= c < n and grid[r][c] == 0
        start = (0, 0, 0)
        goal = (n - 1, n - 2, 0)
        seen = {start}
        q = deque([(start, 0)])
        while q:
            (r, c, h), d = q.popleft()
            if (r, c, h) == goal:
                return d
            cand = []
            if h == 0:
                if free(r, c + 2):
                    cand.append((r, c + 1, 0))
                if free(r + 1, c) and free(r + 1, c + 1):
                    cand.append((r + 1, c, 0))
                    cand.append((r, c, 1))
            else:
                if free(r, c + 1) and free(r + 1, c + 1):
                    cand.append((r, c + 1, 1))
                    cand.append((r, c, 0))
                if free(r + 2, c):
                    cand.append((r + 1, c, 1))
            for s in cand:
                if s not in seen:
                    seen.add(s)
                    q.append((s, d + 1))
        return -1

