var minimumMoves = function(grid) {
    const n = grid.length;
    const free = (r, c) => r >= 0 && r < n && c >= 0 && c < n && grid[r][c] === 0;
    const key = (r, c, h) => r * n * 2 + c * 2 + h;
    const start = [0, 0, 0];
    const goalKey = key(n - 1, n - 2, 0);
    const seen = new Set([key(0, 0, 0)]);
    let q = [[0, 0, 0, 0]];
    let head = 0;
    while (head < q.length) {
        const [r, c, h, d] = q[head++];
        if (key(r, c, h) === goalKey) return d;
        const cand = [];
        if (h === 0) {
            if (free(r, c + 2)) cand.push([r, c + 1, 0]);
            if (free(r + 1, c) && free(r + 1, c + 1)) {
                cand.push([r + 1, c, 0]);
                cand.push([r, c, 1]);
            }
        } else {
            if (free(r, c + 1) && free(r + 1, c + 1)) {
                cand.push([r, c + 1, 1]);
                cand.push([r, c, 0]);
            }
            if (free(r + 2, c)) cand.push([r + 1, c, 1]);
        }
        for (const [nr, nc, nh] of cand) {
            const k = key(nr, nc, nh);
            if (!seen.has(k)) {
                seen.add(k);
                q.push([nr, nc, nh, d + 1]);
            }
        }
    }
    return -1;
};
